xf:input.script:
if (popPeriodCal.getStyle( "display") == "none") {
	$(".f_layer_cal").hide();
	popPeriodCal.setStyle( "display", "");

	if ($p.isPopup()) {
		var clientX = e.clientX - e.offsetX - parseInt($p.getComponentById($p.getPopupId()).getStyle("left").replace("px"));
		var popupWidth = $p.getFrame().getSize("width");

		if(popupWidth - clientX < 570) {
			popPeriodCal.setStyle("right","0px");
		}
	} else {
		if (window.innerWidth > 900) {
			if (window.innerWidth - e.clientX < 500) {
				// var periodX= window.innerWidth - (500 + event.clientX) + "px";
				popPeriodCal.setStyle("right","0px");
				// popPeriodCal.setStyle("left", periodX);
			}
		} else {
			popPeriodCal.setStyle("left", "-120px");
		}
	}
	popPeriodCal.show();
} else {
	popPeriodCal.setStyle("display", "none");
	// popPeriodCal.setStyle("left" ,"0px");
	popPeriodCal.hide();
}

