xf:group.script:
/**
* //property handling
*
* //event trigger
*/
try {
	// ref 설정
	if (ibx_FrDate.getValue() == "" && options.strtDateRef != undefined) {
		ibx_FrDate.setRef(options.strtDateRef);
	}
	if (ibx_ToDate.getValue() == "" && options.endDateRef != undefined) {
		ibx_ToDate.setRef(options.endDateRef);
	}

	// udc의 초기 설정값
	if (ibx_FrDate.getValue() == "" && options.strtDate != undefined) {
		ibx_FrDate.setValue(options.strtDate);
	}
	if (ibx_ToDate.getValue() == "" && options.endDate != undefined) {
		ibx_ToDate.setValue(options.endDate);
	}

	cal_From.gotoCalendar(ibx_FrDate.getValue());
	cal_To.gotoCalendar(ibx_ToDate.getValue());

	// 시작일, 종료일 한꺼번에 구하기
	this.getValue = function() {
		var arg = ibx_FrDate.getValue() + "," + ibx_ToDate.getValue();
		return arg;
	};

	// 시작일, 종료일 한꺼번에 입력
	this.setValue = function(arg1, arg2) {
		ibx_FrDate.setValue(arg1);
		ibx_ToDate.setValue(arg2);
	};

	// 시작일만 입력
	this.setFromDate = function(arg) {
		ibx_FrDate.setValue(arg);
	};

	// 종료일만 입력
	this.setToDate = function(arg) {
		ibx_ToDate.setValue(arg);
	};

	// 시작일 구하기
	this.getFromDate = function() {
		return ibx_FrDate.getValue();
	};

	// 종료일 구하기
	this.getToDate = function() {
		return ibx_ToDate.getValue();
	};

	// 시작일 필수 입력 속성 제어(mandatory) - default는 false
	this.setMandatoryFromDate = function(arg) {
		ibx_FrDate.setMandatory(arg);
	};

	// 종료일 필수 입력 속성 제어(mandatory) - default는 false
	this.setMandatoryToDate = function(arg) {
		ibx_ToDate.setMandatory(arg);
	};

	// 시작일 필수 입력 속성 구하기
	this.getMandatoryFromDate = function() {
		ibx_FrDate.getMandatory();
	};

	// 종료일 필수 입력 속성 구하기
	this.getMandatoryToDate = function() {
		ibx_ToDate.getMandatory();
	};

	// 시작일 ref 입력
	this.setRefFromDate = function(arg) {
		ibx_FrDate.setRef(arg);
	};

	// 종료일 ref 입력
	this.setRefToDate = function(arg) {
		ibx_ToDate.setRef(arg);
	};

	// 시작일 ref 구하기
	this.getRefFromDate = function() {
		ibx_FrDate.getRef();
	};

	// 종료일 ref 구하기
	this.getRefToDate = function() {
		ibx_ToDate.getRef();
	};

	// 확인 클릭시
	this.changePeriod = function() {
		if (cal_From.getValue().length == 8 && cal_To.getValue().length == 8) {
			if (parseInt(cal_From.getValue()) > parseInt(cal_To.getValue())) {
				alert("시작년월일이 종료년월일보다 클수 없습니다.");
				return false;
			}
		}
		ibx_FrDate.setValue(cal_From.getValue());
		ibx_ToDate.setValue(cal_To.getValue());
		//popPeriodCal.setStyle("left", "0px");
		popPeriodCal.hide();
	};
} catch(e) {
}
